import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { orderAPI, userAPI } from '../api/api';
import { useCart } from '../context/CartContext';
import toast from 'react-hot-toast';

export default function CheckoutPage() {
  const { cart, fetchCart } = useCart();
  const navigate = useNavigate();
  const [addresses, setAddresses] = useState([]);
  const [form, setForm] = useState({ shippingAddress: '', shippingCity: '', shippingState: '', shippingZip: '', shippingCountry: 'US', paymentMethod: 'COD' });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    userAPI.getAddresses().then(r => {
      const addrs = r.data.data || [];
      setAddresses(addrs);
      const def = addrs.find(a => a.isDefault) || addrs[0];
      if (def) setForm(prev => ({ ...prev, shippingAddress: def.street, shippingCity: def.city, shippingState: def.state, shippingZip: def.zipCode, shippingCountry: def.country || 'US' }));
    }).catch(() => {});
  }, []);

  const handleChange = (e) => setForm(prev => ({ ...prev, [e.target.name]: e.target.value }));

  const handleSubmit = async () => {
    if (!form.shippingAddress || !form.shippingCity || !form.shippingState || !form.shippingZip) {
      toast.error('Please fill in all shipping fields');
      return;
    }
    setLoading(true);
    try {
      const res = await orderAPI.place(form);
      await fetchCart();
      toast.success('Order placed successfully!');
      navigate(`/orders/${res.data.data.id}`);
    } catch (e) {
      toast.error(e.response?.data?.message || 'Order failed');
    }
    setLoading(false);
  };

  if (!cart.items?.length) {
    navigate('/cart');
    return null;
  }

  return (
    <div className="page-container">
      <h1 className="page-title">Checkout</h1>
      <div className="checkout-layout">
        <div>
          <div className="checkout-section">
            <h3>Shipping Address</h3>
            {addresses.length > 0 && (
              <div style={{ marginBottom: 16 }}>
                {addresses.map(a => (
                  <div key={a.id} className="address-card" style={{ cursor: 'pointer' }}
                    onClick={() => setForm(prev => ({ ...prev, shippingAddress: a.street, shippingCity: a.city, shippingState: a.state, shippingZip: a.zipCode, shippingCountry: a.country || 'US' }))}>
                    <div className="address-label">{a.label || 'Address'} {a.isDefault && <span className="badge badge-accent">Default</span>}</div>
                    <div className="address-text">{a.street}, {a.city}, {a.state} {a.zipCode}</div>
                  </div>
                ))}
              </div>
            )}
            <div className="form-grid">
              <div className="form-group full">
                <label>Street Address</label>
                <input name="shippingAddress" value={form.shippingAddress} onChange={handleChange} placeholder="123 Main St" />
              </div>
              <div className="form-group">
                <label>City</label>
                <input name="shippingCity" value={form.shippingCity} onChange={handleChange} placeholder="New York" />
              </div>
              <div className="form-group">
                <label>State</label>
                <input name="shippingState" value={form.shippingState} onChange={handleChange} placeholder="NY" />
              </div>
              <div className="form-group">
                <label>ZIP Code</label>
                <input name="shippingZip" value={form.shippingZip} onChange={handleChange} placeholder="10001" />
              </div>
              <div className="form-group">
                <label>Country</label>
                <input name="shippingCountry" value={form.shippingCountry} onChange={handleChange} placeholder="US" />
              </div>
            </div>
          </div>

          <div className="checkout-section">
            <h3>Payment Method</h3>
            <div className="payment-options">
              {[
                { value: 'COD', label: 'Cash on Delivery' },
                { value: 'CREDIT_CARD', label: 'Credit Card' },
                { value: 'PAYPAL', label: 'PayPal' },
                { value: 'UPI', label: 'UPI' },
              ].map(opt => (
                <label key={opt.value} className={`payment-option ${form.paymentMethod === opt.value ? 'selected' : ''}`}>
                  <input type="radio" name="paymentMethod" value={opt.value}
                    checked={form.paymentMethod === opt.value} onChange={handleChange} />
                  {opt.label}
                </label>
              ))}
            </div>
          </div>
        </div>

        <div className="cart-summary">
          <h3>Order Summary</h3>
          {cart.items.map(item => (
            <div key={item.id} style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.88rem', padding: '8px 0', borderBottom: '1px solid var(--border)' }}>
              <span style={{ color: 'var(--text-secondary)' }}>{item.product.name} ×{item.quantity}</span>
              <span>${item.lineTotal?.toFixed(2)}</span>
            </div>
          ))}
          <div className="summary-row" style={{ marginTop: 16 }}><span>Subtotal</span><span>${cart.subtotal?.toFixed(2)}</span></div>
          <div className="summary-row"><span>Tax</span><span>${cart.tax?.toFixed(2)}</span></div>
          <div className="summary-row"><span>Shipping</span><span>{cart.shipping > 0 ? `$${cart.shipping?.toFixed(2)}` : 'Free'}</span></div>
          <div className="summary-total"><span>Total</span><span>${cart.total?.toFixed(2)}</span></div>
          <button className="btn btn-primary btn-full btn-lg" onClick={handleSubmit} disabled={loading}>
            {loading ? 'Placing Order...' : `Place Order • $${cart.total?.toFixed(2)}`}
          </button>
        </div>
      </div>
    </div>
  );
}
